import { useState, useRef } from 'react';
import { motion } from 'framer-motion';
import { FiUpload, FiCpu, FiShield } from 'react-icons/fi';

const Hero = () => {
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef(null);

  // Mock detection for demo
  const handleFileUpload = (e) => {
    const file = e.target.files?.[0];
    if (file) {
      alert(`Analyzing: ${file.name}\n(Simulated detection in progress...)`);
    }
  };

  return (
    <section className="relative min-h-[90vh] flex items-center justify-center bg-gradient-to-br from-gray-900 via-purple-900 to-violet-800 overflow-hidden">
      {/* Binary code animation (background) */}
      <div className="absolute inset-0 opacity-20">
        {[...Array(50)].map((_, i) => (
          <motion.span
            key={i}
            className="absolute font-mono text-xs text-green-400"
            style={{
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
            }}
            animate={{ opacity: [0, 1, 0] }}
            transition={{
              duration: 3 + Math.random() * 5,
              repeat: Infinity,
              delay: Math.random() * 2,
            }}
          >
            {Math.random() > 0.5 ? '1' : '0'}
          </motion.span>
        ))}
      </div>

      {/* Main content */}
      <motion.div 
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
        className="relative z-10 text-center px-6 max-w-4xl mx-auto"
      >
        {/* Headline with tech vibe */}
        <h1 className="text-4xl sm:text-5xl md:text-6xl font-bold mb-6">
          <span className="text-white">Unmask </span>
          <span className="text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-emerald-400">
            AI-Generated
          </span>
          <span className="text-white"> Images</span>
        </h1>

        {/* Subtitle with animated border */}
        <motion.p 
          className="text-lg md:text-xl text-gray-300 mb-10 mx-auto max-w-2xl relative px-4 py-2"
          whileHover={{ scale: 1.02 }}
        >
          <motion.span 
            className="absolute inset-0 border border-cyan-400/30 rounded-lg"
            animate={{
              opacity: [0.3, 0.7, 0.3],
            }}
            transition={{
              duration: 4,
              repeat: Infinity,
            }}
          />
          Upload any image to detect AI manipulation with 95%+ accuracy
        </motion.p>

        {/* Interactive upload area */}
        <motion.div
          className={`border-2 border-dashed rounded-xl p-8 mb-10 cursor-pointer transition-colors ${
            isDragging ? 'border-cyan-400 bg-cyan-900/20' : 'border-violet-500 bg-violet-900/10'
          }`}
          onClick={() => fileInputRef.current.click()}
          onDragOver={(e) => {
            e.preventDefault();
            setIsDragging(true);
          }}
          onDragLeave={() => setIsDragging(false)}
          onDrop={(e) => {
            e.preventDefault();
            setIsDragging(false);
            handleFileUpload({ target: { files: e.dataTransfer.files } });
          }}
          whileHover={{ scale: 1.01 }}
        >
          <div className="flex flex-col items-center justify-center space-y-4">
            <FiUpload className="text-4xl text-cyan-400" />
            <p className="text-white font-medium">
              {isDragging ? 'Drop image here' : 'Drag & drop or click to upload'}
            </p>
            <p className="text-sm text-gray-400">Supports JPG, PNG, WEBP (Max 10MB)</p>
          </div>
          <input
            type="file"
            ref={fileInputRef}
            onChange={handleFileUpload}
            accept="image/*"
            className="hidden"
          />
        </motion.div>

        {/* Tech specs indicators */}
        <div className="grid grid-cols-3 gap-4 text-sm">
          {[
            { icon: <FiCpu className="mx-auto text-2xl" />, label: 'Neural Network', value: 'ResNet-50' },
            { icon: <FiShield className="mx-auto text-2xl" />, label: 'Accuracy', value: '95.7%' },
            { icon: <FiClock className="mx-auto text-2xl" />, label: 'Speed', value: '<2s' },
          ].map((item, i) => (
            <motion.div 
              key={i}
              className="bg-gray-800/50 backdrop-blur-sm rounded-lg p-3 border border-gray-700"
              whileHover={{ y: -3 }}
            >
              <div className="text-cyan-400">{item.icon}</div>
              <div className="text-gray-300">{item.label}</div>
              <div className="font-bold text-white">{item.value}</div>
            </motion.div>
          ))}
        </div>
      </motion.div>

      {/* Floating AI visualization */}
      <div className="absolute bottom-10 left-10 w-32 h-32 opacity-70">
        <div className="relative w-full h-full">
          <div className="absolute inset-0 rounded-full bg-cyan-400/20 animate-pulse" />
          <div className="absolute inset-4 rounded-full bg-cyan-400/10 animate-ping" />
        </div>
      </div>
    </section>
  );
};

// Mock icon (install react-icons for real usage)
const FiClock = () => <svg /*...*/ />;

export default Hero;
